#include <bits/stdc++.h>
using namespace std;
const int maxn=3e6+10;
int n,a[maxn],f[maxn];
stack<int>stk;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++)scanf("%d",&a[i]);
	for(int i=1;i<=n;i++){
		while(!stk.empty() && a[stk.top()]<a[i]){
			f[stk.top()]=i;
			stk.pop();
		}
		stk.push(i);
	}
	while(!stk.empty()){
		f[stk.top()]=0;
		stk.pop();
	}
	for(int i=1;i<=n;i++)printf("%d ",f[i]);
	return 0;
}
